field.eval:
{
                'code': 'projects.intake',
                'name': '项目立项',
                'version': 'v2',
                'page': {
                    'key': 'projects.intake.form',
                    'title': '项目立项',
                    'page_type': 'record',
                    'page_mode': 'form'
                },
                'layout': {'kind': 'record', 'sidebar': 'fixed', 'header': 'full'},
                'zone_blocks': [
                    {
                        'key': 'hero',
                        'title': '立项概览',
                        'zone_type': 'hero',
                        'display_mode': 'stack',
                        'block_key': 'block.projects.intake.hero'
                    },
                    {
                        'key': 'form_main',
                        'title': '立项信息',
                        'zone_type': 'primary',
                        'display_mode': 'form',
                        'block_key': 'block.projects.intake.form'
                    },
                    {
                        'key': 'checklist',
                        'title': '提交前检查',
                        'zone_type': 'supporting',
                        'display_mode': 'stack',
                        'block_key': 'block.projects.intake.checklist'
                    }
                ],
                'form_profile': {
                    'model': 'project.project',
                    'view_type': 'form',
                    'mode': 'create_first',
                    'primary_fields': [
                        'name',
                        'partner_id',
                        'manager_id',
                        'date_start',
                        'date_end'
                    ],
                    'required_fields': [
                        'name',
                        'manager_id'
                    ],
                    'submit_action': 'project.initiation.enter'
                },
                'action_specs': {
                    'submit': {
                        'label': '提交立项',
                        'intent': 'ui.contract'
                    },
                    'save_draft': {
                        'label': '保存草稿',
                        'intent': 'api.data'
                    }
                },
                'role_variants': {
                    'pm': {
                        'default_actions': ['submit', 'save_draft'],
                        'focus_zones': ['form_main', 'checklist']
                    },
                    'executive': {
                        'default_actions': ['submit'],
                        'focus_zones': ['hero', 'form_main']
                    }
                },
                'data_sources': {
                    'intake_form': {'source_type': 'odoo_model', 'model': 'project.project'},
                    'intake_defaults': {'source_type': 'computed', 'provider': 'project.intake.defaults'}
                },
                'product_policy': {
                    'role_based': True,
                    'primary_action': 'submit',
                    'stage': 'wave1'
                },
                'target': {
                    'route': '/s/projects.intake',
                    'menu_xmlid': 'smart_construction_core.menu_sc_project_initiation',
                    'action_xmlid': 'smart_construction_core.action_project_initiation'
                }
            }

{
                'code': 'contract.center',
                'name': '合同中心',
                'version': 'v2',
                'page': {
                    'key': 'contract.center.main',
                    'title': '合同中心',
                    'page_type': 'list',
                    'page_mode': 'table'
                },
                'layout': {'kind': 'list', 'sidebar': 'fixed', 'header': 'full'},
                'zone_blocks': [
                    {
                        'key': 'toolbar',
                        'title': '合同快捷入口',
                        'zone_type': 'hero',
                        'display_mode': 'stack',
                        'block_key': 'block.contract.center.toolbar'
                    },
                    {
                        'key': 'contract_list',
                        'title': '合同清单',
                        'zone_type': 'primary',
                        'display_mode': 'table',
                        'block_key': 'block.contract.center.list'
                    },
                    {
                        'key': 'contract_risk',
                        'title': '履约风险',
                        'zone_type': 'supporting',
                        'display_mode': 'stack',
                        'block_key': 'block.contract.center.risk'
                    }
                ],
                'target': {
                    'route': '/s/contract.center',
                    'menu_xmlid': 'smart_construction_core.menu_sc_contract_center',
                    'action_xmlid': 'smart_construction_core.action_construction_contract_my'
                },
                'list_profile': {
                    'model': 'construction.contract',
                    'view_type': 'list',
                    'columns': ['name', 'contract_type', 'state', 'project_id', 'amount_total', 'sign_date'],
                    'column_labels': {
                        'name': '合同名称',
                        'contract_type': '合同类型',
                        'state': '状态',
                        'project_id': '项目',
                        'amount_total': '合同金额',
                        'sign_date': '签订日期'
                    },
                    'row_primary': 'name',
                    'row_secondary': 'project_id'
                },
                'action_specs': {
                    'open_income': {
                        'label': '查看收入合同',
                        'intent': 'ui.contract'
                    },
                    'open_expense': {
                        'label': '查看支出合同',
                        'intent': 'ui.contract'
                    }
                },
                'related_scenes': ['contracts.workspace', 'cost.cost_compare', 'finance.settlement_orders'],
                'default_sort': 'write_date desc'
            }

{
                'code': 'contracts.workspace',
