                    },
                    {
                        'key': 'income_expense',
                        'title': '收支合同执行',
                        'zone_type': 'primary',
                        'display_mode': 'table',
                        'block_key': 'block.contracts.workspace.main'
                    },
                    {
                        'key': 'settlement_watch',
                        'title': '结算与风险',
                        'zone_type': 'supporting',
                        'display_mode': 'stack',
                        'block_key': 'block.contracts.workspace.risk'
                    }
                ],
                'target': {
                    'route': '/s/contracts.workspace',
