{
                'code': 'cost.analysis',
                'name': '成本控制工作台',
                'version': 'v2',
                'portal_only': False,
                'spa_ready': True,
                'page': {
                    'key': 'cost.analysis.workspace',
                    'title': '成本控制工作台',
                    'page_type': 'workspace',
                    'page_mode': 'workspace'
                },
                'layout': {'kind': 'workspace', 'sidebar': 'fixed', 'header': 'full'},
                'zone_blocks': [
                    {
                        'key': 'overview',
                        'title': '成本总览',
                        'zone_type': 'hero',
                        'display_mode': 'stack',
                        'block_key': 'block.cost.analysis.overview'
                    },
                    {
                        'key': 'cost_metrics',
                        'title': '指标看板',
                        'zone_type': 'primary',
                        'display_mode': 'grid',
                        'block_key': 'block.cost.analysis.metrics'
                    },
                    {
                        'key': 'variance',
                        'title': '偏差与预警',
                        'zone_type': 'secondary',
                        'display_mode': 'stack',
                        'block_key': 'block.cost.analysis.variance'
                    }
                ],
                'target': {
                    'route': '/s/cost.analysis',
                    'action_xmlid': 'smart_construction_core.action_project_cost_ledger',
                    'menu_xmlid': 'smart_construction_core.menu_sc_project_cost_ledger'
                },
                'action_specs': {
                    'open_cost_ledger': {
                        'label': '查看成本台账',
                        'intent': 'ui.contract'
                    },
                    'open_profit_compare': {
                        'label': '查看盈亏对比',
                        'intent': 'ui.contract'
                    }
                },
                'role_variants': {
                    'pm': {
                        'default_actions': ['open_cost_ledger'],
                        'focus_zones': ['cost_metrics', 'variance']
                    },
                    'finance': {
                        'default_actions': ['open_profit_compare'],
                        'focus_zones': ['overview', 'variance']
                    }
                },
                'data_sources': {
                    'cost_metrics': {'source_type': 'odoo_model', 'model': 'project.cost.ledger'},
                    'cost_alerts': {'source_type': 'computed', 'provider': 'cost.analysis.alerts'}
                },
                'product_policy': {
                    'role_based': True,
                    'primary_action': 'open_cost_ledger',
                    'stage': 'wave1'
                },
                'related_scenes': ['cost.project_cost_ledger', 'cost.profit_compare', 'contract.center']
            }

{
